"use client";

import type {ColorSliderProps} from "../types";

import {ColorSlider as AriaColorSlider, ColorThumb, SliderTrack} from "react-aria-components";
import {tv} from "tailwind-variants";

import {cn} from "@/utils/cn";
import {focusRing} from "@/utils/focus";

const colorSliderTrackStyles = tv({
  base: "h-8 w-full rounded-full forced-colors:bg-[GrayText]",
  variants: {
    orientation: {
      horizontal: "h-8 w-full",
      vertical: "ml-2 h-full w-8",
    },
  },
});

const colorThumbStyles = tv({
  base: "size-4 cursor-grab rounded-full border-[1.5px] border-white shadow-lg data-[dragging=true]:cursor-grabbing",
  extend: focusRing,
});

export function ColorSlider({
  className,
  orientation = "horizontal",
  thumbBackground,
  trackBackground,
  ...props
}: ColorSliderProps) {
  return (
    <AriaColorSlider
      className={cn("group flex w-full flex-col gap-1", className)}
      orientation={orientation}
      {...props}
    >
      <SliderTrack
        className={colorSliderTrackStyles({orientation})}
        style={({defaultStyle}) => ({
          background: trackBackground || `${defaultStyle.background}`,
        })}
      >
        <ColorThumb
          className={cn(colorThumbStyles(), orientation === "horizontal" ? "top-1/2" : "left-1/2")}
          style={({color}) => ({
            background: thumbBackground || color.toString("css"),
          })}
        />
      </SliderTrack>
    </AriaColorSlider>
  );
}

"use client";

import {Chip} from "@heroui/react";
import * as React from "react";

import {useDictionary} from "@/hooks/use-dictionary";

export type StatusChipStatus = "new" | "new-dot" | "preview" | "updated";

interface StatusChipProps {
  status: StatusChipStatus;
  className?: string;
}

export function StatusChip({className, status}: StatusChipProps) {
  const dict = useDictionary().statusChip;

  if (status === "new") {
    return (
      <Chip
        className={`h-5 rounded-full bg-pink-400/8 px-1.5 text-[10px] font-semibold text-pink-400/90 ${className || ""}`}
        variant="primary"
      >
        {dict.new}
      </Chip>
    );
  }

  if (status === "preview") {
    return (
      <Chip
        className={`h-5 rounded-full border border-foreground/10 px-1.5 text-[10px] text-foreground/60 ${className || ""}`}
        variant="tertiary"
      >
        {dict.preview}
      </Chip>
    );
  }

  if (status === "updated") {
    return (
      <Chip
        className={`h-5 rounded-full bg-black/3 px-1.5 text-[10px] text-muted/90 dark:bg-white/8 ${className || ""}`}
        variant="primary"
      >
        {dict.updated}
      </Chip>
    );
  }

  return null;
}

export default StatusChip;

